configuration.jsScript:
try {
    // 1. Filtramos que solo sean paquetes de datos
    if (msgType !== 'POST_ATTRIBUTES_REQUEST' && msgType !== 'POST_TELEMETRY_REQUEST') {
        return false;
    }

    // 2. ¿El equipo confirma que se recuperó? (Ruta False -> Limpia la alarma)
    if (msg.hasOwnProperty('estado_cerrado')) {
        var cerrado = msg.estado_cerrado;
        if (cerrado === true || cerrado === 1 || cerrado === "1" || cerrado === "true") {
            return false; 
        }
    }

    // 3. ¿El equipo confirma una falla? (Ruta True -> Crea la alarma hacia Telegram)
    if (msg.hasOwnProperty('estado_abierto')) {
        var abierto = msg.estado_abierto;
        if (abierto === true || abierto === 1 || abierto === "1" || abierto === "true") {
            return true; 
        }
    }

    // Si el paquete es de otra cosa (ej. voltaje), lo mandamos por False en silencio
    return false;

} catch (err) {
    return false;
}

