configuration.jsScript:
// 1. Extraemos el tipo de falla desde los metadatos (el 'Alarm Type' del nodo Create Alarm)
var tipo_falla = metadata.alarmType || metadata.type || "Anomalía No Identificada";

// 2. Definimos el esqueleto del mensaje
var texto_mensaje = "🚨 ALERTA DEL SCADA (OSM27) 🚨\n\n";

// 3. Lógica condicional para personalizar el mensaje
// IMPORTANTE: Los nombres entre comillas deben ser EXACTAMENTE IGUALES a los que 
// escribiste en el campo "Alarm Type" de tus nodos "Create Alarm" en ThingsBoard.
switch (tipo_falla) {
    case "Sobrecorriente":
    case "Cortocircuito":
        texto_mensaje += "⚡ CRÍTICO: Cortocircuito detectado (Pickup).\n⚠️ Las corrientes de fase superaron el umbral. El equipo se prepara para abrir contactos e iniciar reenganche.";
        break;

    case "SAG":
    case "Falla SAG":
        texto_mensaje += "📉 ALERTA: Hueco de Tensión (SAG) detectado.\n⚠️ El voltaje de red ha caído. Esperando estabilización.";
        break;

    case "Lockout":
    case "Falla Lockout":
        texto_mensaje += "🛑 BLOQUEO (LOCKOUT ANSI 79).\n❌ Falla permanente en la línea. El reconectador ha agotado los 3 intentos. Requiere inspección de línea y comando de RESET manual.";
        break;

    case "Falla Equipo Abierto":
        texto_mensaje += "🔓 AVISO: Cambio de estado.\nℹ️ Los contactos del reconectador están ABIERTOS. Línea desenergizada.";
        break;

    default:
        texto_mensaje += "ℹ️ AVISO: Registro de evento de red: [" + tipo_falla + "].";
}

// 4. Agregamos un timestamp formateado con la hora local de Argentina
var opcionesHora = { timeZone: "America/Argentina/Buenos_Aires", hour12: false };
var fechaLocal = new Date().toLocaleString("es-AR", opcionesHora);

texto_mensaje += "\n\n📅 Fecha/Hora: " + fechaLocal;

// 5. Empaquetamos para la API REST de Telegram
var telegramPayload = {
    "chat_id": "6174555600", // Tu ID de Telegram
    "text": texto_mensaje
};

return {msg: telegramPayload, metadata: metadata, msgType: msgType};

