if (metadata.prevAlarmDetails) {
    details = JSON.parse(metadata.prevAlarmDetails);
    //remove prevAlarmDetails from metadata
    delete metadata.prevAlarmDetails;
    //now metadata is the same as it comes IN this rule node
}


return details;

configuration.alarmDetailsBuildTbel:
var details = {};
if (metadata.prevAlarmDetails != null) {
    details = JSON.parse(metadata.prevAlarmDetails);
    //remove prevAlarmDetails from metadata
    metadata.remove('prevAlarmDetails');
    //now metadata is the same as it comes IN this rule node
}


return details;

configuration.jsScript:
var links = [];

// 1. Evaluar Cortocircuito (Pickup)
if (typeof msg.pickup !== 'undefined') {
    if (msg.pickup === true) {
        links.push("Alarma_Corto");
    } else {
        links.push("Limpiar_Corto");
    }
}

// 2. Evaluar Hueco de Tensión (Sag)
if (typeof msg.sag !== 'undefined') {
    if (msg.sag === true) {
        links.push("Alarma_SAG");
    } else {
        links.push("Limpiar_SAG");
    }
}

// 3. Evaluar Bloqueo (Lockout 79)
if (typeof msg.lockout !== 'undefined') {
    if (msg.lockout === true) {
        links.push("Alarma_Lockout");
    } else {
        links.push("Limpiar_Lockout");
    }
}

// 4. Evaluar Estado del Equipo (Apertura)
if (typeof msg.estado_abierto !== 'undefined') {
    if (msg.estado_abierto === true) {
        links.push("Alarma_Equipo_Abierto");
    } else {
        links.push("Limpiar_Equipo_Abierto");
    }
}

return links;

